const linkedSongs = (artistName: string) => songs.filter((song) => song.artist === artistName);
const linkedAlbums = (artistName: string) => albums.filter((album) => album.artist === artistName);

const makeArtist = ({
  id,
  name,
  years,
  region,
  styles,
  tagline,
  bio,
  color,
  portrait,
  highlights,
  collaborations,
  influences,
  awards,
  instruments,
  label,
  quotes,
  anecdotes,
  chronology,
  concerts,
  singles,
  internalLinks
}: {
  id: string;
  name: string;
  years: string;
  region: string;
  styles: string[];
  tagline: string;
  bio: string;
  color: string;
  portrait: string;
  highlights: string[];
  collaborations: string[];
  influences: string[];
  awards: string[];
  instruments: string[];
  label: string;
  quotes: string[];
  anecdotes: string[];
  chronology?: string[];
  concerts?: string[];
  singles?: string[];
  internalLinks?: string[];
}): Artist => ({
  id,
  name,
  years,
  region,
  styles,
  tagline,
  bio,
  hero: visual(`Portrait illustre de ${name}`, 'portrait', color, portrait),
  gallery: [
    visual(`Photo de scene de ${name}`, 'stage', color, media.stage),
    visual(`Pochette ou archive de ${name}`, 'album', color, media.vinyl),
    visual(`Affiche patrimoniale de ${name}`, 'poster', color, media.poster),
    visual(`Document historique de ${name}`, 'archive', color, media.archive)
  ],
  albums: linkedAlbums(name),
  songs: linkedSongs(name),
  highlights,
  collaborations,
  influences,
  awards,
  instruments,
  label,
  quotes,
  anecdotes,
  chronology: chronology ?? [`Debuts - Construction de l’univers ${styles[0]}.`, `Periode phare - Titre ou album majeur a documenter.`, `Heritage - Reprises, hommages et influence dans la chanson francaise.`],
  concerts: concerts ?? ['Olympia ou grande salle a documenter', 'Plateaux television', 'Tournees francophones', 'Archives live a collecter'],
  singles: singles ?? linkedSongs(name).map((song) => song.title),
  internalLinks: internalLinks ?? [...styles.slice(0, 2), ...linkedAlbums(name).map((album) => album.title), ...collaborations.slice(0, 2)]
});

